metadata.output:
spec-memory memory_search

Description:
  [L2:Core] Search indexed spec-doc continuity semantically using vector similarity. Returns ranked results with similarity scores. Constitutional tier rules are ALWAYS included at the top of results (~2000 tokens max), regardless of query. Requires query (string), concepts (array of 2-5 strings), or cursor (string) for continuation pagination. Supports intent-aware retrieval (REQ-006) with task-specific weight adjustments. When implicit feedback logging is enabled, searches also emit shadow-only feedback signals such as search_shown and, for includeContent runs, result_cited. Token Budget: 3500. For code search, use mcp__mk_code_index__code_graph_query for structural code queries (callers, imports) and Grep for exact text or token searches.

Aliases:
  memory_search, memory-search, memorySearch

Input schema:
{
  "type": "object",
  "additionalProperties": false,
  "x-requiredAnyOf": [
    [
      "query"
    ],
    [
      "concepts"
    ],
    [
      "cursor"
    ]
  ],
  "properties": {
    "cursor": {
      "type": "string",
      "minLength": 1,
      "description": "Opaque continuation cursor returned by progressive disclosure. When provided, resolves the next page without requiring a new query."
    },
    "query": {
      "type": "string",
      "minLength": 2,
      "maxLength": 1000,
      "description": "Natural language search query"
    },
    "concepts": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "minItems": 2,
      "maxItems": 5,
      "description": "Multiple concepts for AND search (requires 2-5 concepts). Results must match ALL concepts."
    },
    "specFolder": {
      "type": "string",
      "description": "Limit search to a specific spec folder (e.g., \"011-spec-kit-memory-upgrade\")"
    },
    "tenantId": {
      "type": "string",
      "description": "Tenant boundary for governed retrieval. When provided with scope enforcement, results are isolated to this tenant."
    },
    "userId": {
      "type": "string",
      "description": "User boundary for governed retrieval. Filters private user-scoped spec-doc records."
    },
    "agentId": {
      "type": "string",
      "description": "Agent boundary for governed retrieval. Filters agent-scoped spec-doc records."
    },
    "limit": {
      "type": "number",
      "default": 10,
      "minimum": 1,
      "maximum": 100,
      "description": "Maximum number of results to return (1-100)"
    },
    "sessionId": {
      "type": "string",
      "description": "Session identifier for working memory and session deduplication (REQ-001). When provided with enableDedup=true, prevents duplicate spec-doc records from being returned in the same session (~50% token savings on follow-up queries)."
    },
    "enableDedup": {
      "type": "boolean",
      "default": true,
      "description": "Enable session deduplication (REQ-001). When true and sessionId provided, filters out already-sent spec-doc records."
    },
    "tier": {
      "type": "string",
      "description": "Filter by importance tier (constitutional, critical, important, normal, temporary, deprecated)"
    },
    "contextType": {
      "type": "string",
      "description": "Filter by context type (decision, implementation, research, etc.)"
    },
    "useDecay": {
      "type": "boolean",
      "default": true,
      "description": "Apply temporal decay scoring to results"
    },
    "includeContiguity": {
      "type": "boolean",
      "default": false,
      "description": "Include adjacent/contiguous spec-doc records (from the same packet, neighboring sections) in results"
    },
    "includeConstitutional": {
      "type": "boolean",
      "default": true,
      "description": "Include constitutional tier rules at top of results (default: true)"
    },
    "enableSessionBoost": {
      "type": "boolean",
      "description": "Enable session-based score boost from working_memory attention signals. Defaults to SPECKIT_SESSION_BOOST env flag."
    },
    "enableCausalBoost": {
      "type": "boolean",
      "description": "Enable causal-neighbor boost (2-hop traversal on causal_edges). Defaults to SPECKIT_CAUSAL_BOOST env flag."
    },
    "includeContent": {
      "type": "boolean",
      "default": false,
      "description": "Include full file content in results. When true, each result includes a \"content\" field with the spec-doc file contents. This embeds load logic directly in search, eliminating the need for separate load calls. When implicit feedback logging is enabled, includeContent searches also emit shadow-only result_cited events for returned spec-doc records."
    },
    "anchors": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Specific anchor IDs to extract from content. If provided, returned content will be filtered to only these sections. Requires includeContent: true."
    },
    "profile": {
      "type": "string",
      "enum": [
        "quick",
        "research",
        "resume",
        "debug"
      ],
      "description": "Optional response profile formatter. Returns a reduced or mode-aware response shape when profile formatting is enabled."
    },
    "min_quality_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Minimum quality score threshold (0.0-1.0). Results with lower quality_score are filtered out."
    },
    "minQualityScore": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Deprecated alias for min_quality_score. Prefer snake_case parameter name."
    },
    "bypassCache": {
      "type": "boolean",
      "default": false,
      "description": "Skip the tool cache and force a fresh search. Useful when underlying data has changed since last cached result."
    },
    "rerank": {
      "type": "boolean",
      "default": true,
      "description": "Enable Stage-3 MMR diversity reranking (reduces near-duplicate results) plus MPAB chunk collapse. Default true."
    },
    "applyLengthPenalty": {
      "type": "boolean",
      "default": true,
      "description": "Apply length-based penalty during reranking. Penalizes very long spec-doc records to favor concise, focused results. Only effective when rerank is true."
    },
    "applyStateLimits": {
      "type": "boolean",
      "default": false,
      "description": "Apply per-tier quantity limits to results. When true, enforces maximum counts per state tier to balance result diversity."
    },
    "minState": {
      "type": "string",
      "enum": [
        "HOT",
        "WARM",
        "COLD",
        "DORMANT",
        "ARCHIVED"
      ],
      "default": "WARM",
      "description": "Minimum spec-doc record state to include in results. Records below this state are filtered out. Order: HOT > WARM > COLD > DORMANT > ARCHIVED."
    },
    "intent": {
      "type": "string",
      "enum": [
        "add_feature",
        "fix_bug",
        "refactor",
        "security_audit",
        "understand",
        "find_spec",
        "find_decision"
      ],
      "description": "Task intent for weight adjustments (REQ-006). Explicitly set query intent to optimize scoring for specific tasks."
    },
    "autoDetectIntent": {
      "type": "boolean",
      "default": true,
      "description": "Auto-detect intent from query if not explicitly specified. When true, classifies query to apply task-specific scoring weights."
    },
    "trackAccess": {
      "type": "boolean",
      "default": false,
      "description": "When true, writes FSRS strengthening updates to the memory_index for each returned spec-doc record. Off by default to avoid write-on-read side effects."
    },
    "includeArchived": {
      "type": "boolean",
      "default": false,
      "description": "Not supported: archived spec-doc records are always excluded by canonical-source policy. This flag is accepted for back-compat but has no effect."
    },
    "mode": {
      "type": "string",
      "enum": [
        "auto",
        "deep"
      ],
      "default": "auto",
      "description": "Search mode. \"auto\" uses standard retrieval. \"deep\" enables multi-query expansion for broader recall."
    },
    "includeTrace": {
      "type": "boolean",
      "default": false,
      "description": "When true (or when SPECKIT_RESPONSE_TRACE=true), include provenance-rich scores/source/trace envelope fields in each result."
    },
    "retrievalLevel": {
      "type": "string",
      "enum": [
        "local",
        "global",
        "auto"
      ],
      "default": "auto",
      "description": "Graph retrieval scope for entity- vs community-level search: \"local\" returns entity-level matches only; \"global\" and \"auto\" (default) also permit a community-level fallback (graph community detection) when direct matches are sparse."
    }
  }
}

